class Solution(object):
    def summaryRanges(self, nums):
        """
        :type nums: List[int]
        :rtype: List[str]
        """
        n = len(nums)
        if n == 0:
            return []

        result = []
        start = end = nums[0]
        for i in range(1, n):
            if nums[i] - nums[i-1] > 1:
                if start!= end:
                    result.append(str(start) + "->" + str(end))
                else:
                    result.append(str(start))
                start = end = nums[i]

