class Solution(object):
    def isMatch(self, s, p):
        """
        :type s: str
        :type p: str
        :rtype: bool
        """
        # Initialize a table with all False values
        match = [[False]*(len(p)+1) for _ in range(len(s)+1)]

        # Initialize the first column to True, because an empty pattern can always match an empty string
        for i in range(len(s)+1):
            match[i][0] = True

        # Process the pattern and the string, comparing each character
        for i in range(1, len(s)+1):
            for j in range(1, len(p)+1):
                # If the current pattern character is '*'
                if p[j-1] == '*':
                    # If the previous character is a match
                    if match[i-1][j-2] or p[j-2] == '*':
                        match[i][j] = True
                # If the current pattern character is '.' or it matches the current string character
                elif p[j-1] == '.' or p[j-1] == s[i-1]:
                    match[i][j] = match[i-1][j-1]

        # The last cell of the table is the answer
        return match[-1][-1]

