from heapq import nlargest

class Solution(object):
    def maxNumber(self, nums1, nums2, k):
        def merge(a, b, k):
            i, j, n, m = 0, 0, len(a), len(b)
            while i < n and j < m:
                if a[i] > b[j]:
                    a[i], b[j] = b[j], a[i]
                    j += 1
                else:
                    i += 1
            while j < m:
                a[i], b[j] = b[j], a[i]
                j += 1
            while i < n:
                a[i], a[n-1] = a[n-1], a[i]
                i += 1
                n -= 1
            for i in range(n-1, -1, -1):
                if a[i] == 0:
                    a.pop(i)
                    n -= 1
                else:
                    break
            return a[:n]

        nums1, nums2 = sorted(nums1, reverse=True), sorted(nums2, reverse=True)
        ans = [0]*k
        for i in range(min(k, len(nums1))):
            ans[i] = max(nlargest(k, nums1[:i+1], key=lambda x: (x, -i)))
        for i in range(min(k, len(nums2))):
            ans[i+len(nums1)] = max(nlargest(k-len(nums1), nums2[:i+1], key=lambda x: (x, -i)))
        return merge(ans, [0]*(len(nums1)+len(nums2)), k)

