    def checkPerfectNumber(self, num):
        """
        :type num: int
        :rtype: bool
        """
        if num < 6:
            return False
        # Check from 2 to sqrt(num)
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                # If num is divisible by i, then check if there is any other divisor
                if i == (num / i):
                    # If i is equal to num/i, then it means there is no other divisor except i and num/i
                    # So, we can return True
                    return True
                else:
                    # If i is not equal to num/i, then there must be other divisors
                    # So, we can return False
                    return False
        # If no divisors found, then num is a perfect number
        return True

