class Solution(object):
    def toHex(self, num):
        """
        :type num: int
        :rtype: str
        """
        # Define the hexadecimal characters
        hex_chars = "0123456789abcdef"

        # If the number is negative, convert it to its absolute value and add 'f' at the end
        if num < 0:
            num = abs(num)
            hex_str = "ffffffff"
        else:
            hex_str = ""

        # Convert the number to hexadecimal
        while num > 0:
            hex_str = hex_chars[num % 16] + hex_str
            num //= 16

        # Remove leading zeros
        return hex_str.lstrip('0')

