class Solution(object):
    def containsNearbyAlmostDuplicate(self, nums, indexDiff, valueDiff):
        """
        :type nums: List[int]
        :type indexDiff: int
        :type valueDiff: int
        :rtype: bool
        """
        if indexDiff < 0 or valueDiff < 0:
            return False

        if len(nums) <= 2 * indexDiff + 1:
            return True

        nums_dict = defaultdict(list)
        for i, num in enumerate(nums):
            nums_dict[num].append(i)

        for nums_list in nums_dict.values():
            if len(nums_list) <= 1:
                continue
            nums_list.sort()
            for i in range(len(nums_list) - 1):
                if nums_list[i+1] - nums_list[i] <= indexDiff and abs(nums[nums_list[i]] - nums[nums_list[i+1]]) <= valueDiff:
                    return True

        return False

