def maximumGap(self, nums):
    if len(nums) < 2:
        return 0
    nums.sort()
    max_diff = 0
    slist = SortedList()
    for num in nums:
        idx = slist.bisect_left(num)
        if idx == 0:
            max_diff = max(max_diff, num - slist[0])
        else:
            max_diff = max(max_diff, slist[idx] - num)
        slist.add(num)
    return max_diff

