class Solution(object):
    def grayCode(self, n: int) -> List[int]:
        if n == 0:
            return [0]
        if n == 1:
            return [0, 1]
        if n == 2:
            return [0, 1, 3, 2]

        # Initialize the base case
        base = [0, 1, 3, 2]
