class Solution(object):
    def partition(self, s):
        """
        :type s: str
        :rtype: List[List[str]]
        """
        # Create a 2D list to store the partition information
        # Initialize the first row and column with all zeros
        # Initialize the first element of each row with True
        # Initialize the first row of each column with False
        partition = [[0]*(len(s)+1) for _ in range(len(s)+1)]
        for i in range(len(s)):
            partition[i][i] = True
        for i in range(len(s)-1, -1, -1):
            for j in range(i+1, len(s)+1):
                # Check if the substring from i to j is a palindrome
                if s[i] == s[j-1] and (j-i <= 2 or partition[i+1][j-1]):
                    partition[i][j] = True

        # Use the partition information to generate all possible palindrome partitioning
        result = []
        self.generate_partition(s, partition, 0, [], result)
        return result

    def generate_partition(self, s, partition, start, partition_list, result):
        if start == len(s):
            result.append(partition_list[::-1])
        else:
            for i in range(start, len(s)):
                if partition[start][i] and i-start+1 > len(partition_list):
                    partition_list.append(s[start:i+1])
                    self.generate_partition(s, partition, i+1, partition_list, result)
                    partition_list.pop()

