    def wordBreak(self, s, wordDict):
        """
        :type s: str
        :type wordDict: List[str]
        :rtype: List[str]
        """
        # Initialize a list to keep track of whether a substring can be segmented into words in the dictionary.
        # Initially, all substrings can be segmented, i.e., they are not segmented initially.
        can_segment = [False] * (len(s) + 1)
        # The first substring that can be segmented is an empty string, which is always segmented.
        can_segment[0] = True

        # For each substring from 1 to n, check if it can be segmented.
        # If the substring can be segmented, then check if it can be segmented into words in the dictionary.
        for i in range(1, len(s) + 1):
            for j in range(i):
                # If the substring from j to i-1 can be segmented and the substring from j to i-1 can be segmented into words in the dictionary, then the substring from j to i can be segmented.
                if can_segment[j] and s[j:i] in wordDict:
                    can_segment[i] = True

        # If the whole string can be segmented, then generate all the possible segmentations.
        if can_segment[-1]:
            return self.generate_segmentations(s, wordDict, len(s), [])
        else:
            return []

    def generate_segmentations(self, s, wordDict, i, segmentations):
        # If the current substring has been segmented, then add it to the current segmentation.
        if i > 0:
            segmentations.append(s[i-1:i])
        # If the current substring can be segmented into words in the dictionary, then recursively generate all the possible segmentations for the remaining substring.
        if s[i-1:i] in wordDict:
            for j in range(i-1, 0, -1):
                if can_segment[j]:
                    self.generate_segmentations(s, wordDict, j, segmentations)
        # If the current substring cannot be segmented into words in the dictionary, then remove it from the current segmentation and try the next substring.
        else:
            segmentations.pop()

