class Solution(object):
    def isMatch(self, s, p):
        """
        :type s: str
        :type p: str
        :rtype: bool
        """
        # Initialize a 2D DP table with all entries as False
        dp = [[False]*(len(p)+1) for _ in range(len(s)+1)]

        # If pattern is empty, only if string is empty then match
        for i in range(len(s)+1):
            dp[i][0] = True

        # If pattern is not empty and string is empty, no match
        for i in range(1, len(p)+1):
            if p[i-1]!= '*' and p[i-1]!= '?':
                dp[0][i] = False

        # Fill in the DP table
        for i in range(1, len(s)+1):
            for j in range(1, len(p)+1):
                if p[j-1] == '*':
                    # If pattern character is '*', then check for previous characters
                    dp[i][j] = dp[i][j-1] or dp[i-1][j]
                elif p[j-1] == '?':
                    # If pattern character is '?', then check for previous characters
                    dp[i][j] = dp[i-1][j-1]
                else:
                    # If pattern character is not '*', then check for previous characters
                    dp[i][j] = dp[i-1][j-1] and (s[i-1] == p[j-1] or p[j-1] == '?')

        # Return the last cell of the DP table as the result
        return dp[-1][-1]

