    def maxProfit(self, prices):
        """
        :type prices: List[int]
        :rtype: int
        """
        n = len(prices)
        if n <= 1:
            return 0

        # dp[i][j] means the maximum profit we can get if we buy on day i and sell on day j.
        dp = [[0]*n for _ in range(n)]
        for i in range(n):
            dp[i][i] = 0

        for gap in range(1, n):
            for i in range(n-gap):
                j = i+gap
                # if we sell on day j and buy on day i, we can get profit prices[j] - prices[i]
                # but if we sell on day j and buy on day i+1, we need to hold the stock for one more day.
