from collections import defaultdict, deque

class Solution(object):
    def findLadders(self, beginWord, endWord, wordList):
        # Create a graph with words as nodes and edges as valid transitions
        graph = defaultdict(list)
        for word in wordList:
            for i in range(len(word)):
                for j in range(i+1, len(word)+1):
                    nei = word[:i] + "_" + word[j:]
                    graph[nei].append(word)
        # BFS from beginWord to reach endWord
        queue = deque([(beginWord, [beginWord])])
        while queue:
            word, path = queue.popleft()
            for nei in graph[word]:
                if nei not in path:
                    if nei == endWord:
                        yield path + [nei]
                    else:
                        queue.append((nei, path + [nei]))
        # Convert the yielded paths into the required format
        return [path[::-1] for path in list(set(map(lambda path: path[::-1], yield)))]

