    def maxEnvelopes(self, envelopes):
        """
        :type envelopes: List[List[int]]
        :rtype: int
        """
        # Sort the envelopes by width first, then by height
        envelopes.sort(key=lambda x: (x[0], -x[1]))
        n = len(envelopes)
        # Initialize the dp array with zeros
        dp = [0]*n
        # Iterate through the sorted envelopes
        for i in range(n):
            # If the current envelope is not nested, it can be put in
            if i == 0 or envelopes[i][0] > envelopes[i-1][0] and envelopes[i][1] > envelopes[i-1][1]:
                dp[i] = 1
            # If the current envelope is nested, it needs to be put in if it can be put in the previous envelope
            else:
                dp[i] = dp[i-1]
            # Update the maximum number of envelopes that can be put in
            for j in range(i):
                if envelopes[i][0] > envelopes[j][0] and envelopes[i][1] > envelopes[j][1] and dp[i] < dp[j] + 1:
                    dp[i] = dp[j] + 1
        # The maximum number of envelopes that can be put in is the maximum value in the dp array
        return max(dp)

