        :type board: List[List[str]]
        :rtype: None Do not return anything, modify board in-place instead.
        """
        def is_valid(board, row, col, num):
            # Check if 'num' is valid in 'row'
            for x in range(9):
                if board[row][x] == num:
                    return False
            # Check if 'num' is valid in 'col'
            for x in range(9):
                if board[x][col] == num:
                    return False
            # Check if 'num' is valid in box
            start_row, start_col = row - row % 3, col - col % 3
            for i in range(3):
                for j in range(3):
                    if board[i + start_row][j + start_col] == num:
                        return False
            return True

        def solve(board):
            for i in range(9):
                for j in range(9):
                    if board[i][j] == ".":
                        for num in "123456789":
                            if is_valid(board, i, j, num):
                                board[i][j] = num  # Make tentative assignment
                                if solve(board):  # If succeed, continue to fill the rest of the board
                                    return True
                                else:  # If not succeed, undo the assignment and try a different number
                                    board[i][j] = "."
                        return False  # If no valid number can be assigned, backtrack
            return True  # If all cells are filled, the puzzle is solved

        if board:
            solve(board)

