class Solution(object):
    def isPerfectSquare(self, num):
        """
        :type num: int
        :rtype: bool
        """
        # If number is 0 or 1, it is a perfect square
        if num <= 1:
            return True

        # Binary search approach to find the square root
        start, end = 2, num // 2
        while start <= end:
            mid = (start + end) // 2
            square = mid * mid
            if square == num:
                return True
            elif square < num:
                start = mid + 1
            else:
                end = mid - 1
        return False

