class Solution(object):
    def numberOfArithmeticSlices(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        n = len(nums)
        if n < 3: return 0
        nums = sorted(set(nums))
        dp = defaultdict(int)
        for i in range(n):
            dp[i] = 0
            for j in range(i):
                if nums[i] - nums[j] == nums[j] - nums[i]:
                    dp[i] += dp[j]
        return sum(dp.values())

