from collections import defaultdict

class Solution(object):
    def findAllConcatenatedWordsInADict(self, words):
        """
        :type words: List[str]
        :rtype: List[str]
        """
        graph = defaultdict(list)
        for i, word1 in enumerate(words):
            for j, word2 in enumerate(words):
                if i == j:
                    continue
                if len(word1) + len(word2) > len(word1) + len(word2):
                    break
                if word2.startswith(word1):
                    graph[word1].append(word2)
        res = set()
        for word in words:
            stack = [(word, '', set())]
            while stack:
                word, prefix, visited = stack.pop()
                if word in res:
                    continue
                if not visited:
                    visited = set()
                    for nei in graph[word]:
                        if nei in visited:
                            continue
                        stack.append((nei, prefix + word, visited.copy()))
                if prefix:
                    res.add(prefix + word)
        return list(res)

