class Solution(object):
    def totalNQueens(self, n):
        def canPlace(pos, i):
            # Check if the queen can be placed in the same row
            if pos[i] == pos[i-1]:
                return False
            # Check if the queen can be placed in the same column
            if i > 1 and pos[i] == pos[i-2]:
                return False
            # Check if the queen can be placed diagonally
            if i > 1 and pos[i-1] == pos[i-2] + (pos[i] - pos[i-1]) and pos[i] - pos[i-1]!= 0:
                return False
            if i > 1 and pos[i-1] == pos[i-2] - (pos[i] - pos[i-1]) and pos[i] - pos[i-1]!= 0:
                return False
            return True

        def solveNQ(n, pos):
            if n == 1:
                return 1
            total = 0
            for i in xrange(n):
                if canPlace(pos, i):
                    pos[i], pos[n-1] = pos[n-1], pos[i]
                    total += solveNQ(n-1, pos)
                    pos[i], pos[n-1] = pos[n-1], pos[i]
            return total

        return solveNQ(n, [0]*n)

