        if len(word) > len(board) * len(board[0]) or len(word) == 0:
            return False

        # Check if the word exists in the board
        for i in range(len(board)):
            for j in range(len(board[0])):
                # If the current cell is the first character of the word, perform DFS
                if board[i][j] == word[0]:
                    if self.dfs(board, word, i, j):
                        return True

        # If the word doesn't exist in the board, return False
        return False

    def dfs(self, board, word, i, j):
        # Check if the current cell is out of bounds or the word is empty
        if i < 0 or i >= len(board) or j < 0 or j >= len(board[0]) or len(word) == 0:
            return False

        # Check if the current cell is the last character of the word or the current cell is not the same as the first character of the word
        if word[-1]!= board[i][j]:
            return False

        # Check if the current cell has been visited before
        if board[i][j] == '$':
            return False

        # If the current cell is the same as the first character of the word, mark it as visited and recursively check the remaining word
        board[i][j] = '$'
        if self.dfs(board, word, i-1, j) or self.dfs(board, word, i+1, j) or self.dfs(board, word, i, j-1) or self.dfs(board, word, i, j+1):
